operations.schema:
input InitializeConfigInput {
    name: String!
    domain: String!
    updatedAt: DateTime!
}

operations.reducer:
state.name = action.input.name;
state.domain = action.input.domain;
state.updatedAt = action.input.updatedAt;

if (!state.dimensions) state.dimensions = {
    granularity: { value: 3, confidence: 0.5, rationale: null },
    organization: { value: 3, confidence: 0.5, rationale: null },
    linking: { value: 3, confidence: 0.5, rationale: null },
    processing: { value: 3, confidence: 0.5, rationale: null },
    navigation: { value: 3, confidence: 0.5, rationale: null },
    maintenance: { value: 3, confidence: 0.5, rationale: null },
    schema: { value: 3, confidence: 0.5, rationale: null },
    automation: { value: 3, confidence: 0.5, rationale: null },
};
const dim = action.input.dimension;
if (dim in state.dimensions) {
    (state.dimensions as any)[dim] = {
        value: action.input.value,
        confidence: action.input.confidence,
        rationale: action.input.rationale || null,
    };
}
state.updatedAt = action.input.updatedAt;

operations.schema:
input UpdateVocabularyInput {
    key: String!
    value: String!
    updatedAt: DateTime!
}

operations.reducer:
if (!state.vocabulary) state.vocabulary = {
    notes: "notes", inbox: "inbox", reduce: "reduce", reflect: "reflect",
    reweave: "reweave", verify: "verify", rethink: "rethink",
    topicMap: "topic map", description: "description",
};
if (action.input.key in state.vocabulary) {
    (state.vocabulary as any)[action.input.key] = action.input.value;
}
state.updatedAt = action.input.updatedAt;

operations.schema:
input UpdatePipelineConfigInput {
    depth: String
    autoChain: Boolean
    extractionSelectivity: Float
    updatedAt: DateTime!
}

operations.reducer:
if (!state.pipeline) state.pipeline = { depth: "standard", autoChain: false, extractionSelectivity: 0.1 };
if (action.input.depth) state.pipeline.depth = action.input.depth;
if (action.input.autoChain !== undefined && action.input.autoChain !== null) state.pipeline.autoChain = action.input.autoChain;
if (action.input.extractionSelectivity !== undefined && action.input.extractionSelectivity !== null) state.pipeline.extractionSelectivity = action.input.extractionSelectivity;
state.updatedAt = action.input.updatedAt;

operations.schema:
input UpdateMaintenanceThresholdInput {
    condition: String!
    threshold: Int!
    updatedAt: DateTime!
}

operations.reducer:
if (!state.maintenance) state.maintenance = {
    orphanThreshold: 1, danglingThreshold: 1, inboxPressure: 5,
    observationAccumulation: 10, tensionAccumulation: 5, mocOversize: 40, staleNoteDays: 30,
};
if (action.input.condition in state.maintenance) {
    (state.maintenance as any)[action.input.condition] = action.input.threshold;
}
state.updatedAt = action.input.updatedAt;

operations.schema:
input AddExtractionCategoryInput {
    id: OID!
    name: String!
    description: String!
    active: Boolean!
}

operations.reducer:
state.extractionCategories.push({
    id: action.input.id,
    name: action.input.name,
    description: action.input.description,
    active: action.input.active,
});

operations.schema:
input ToggleExtractionCategoryInput {
    id: OID!
    active: Boolean!
}

input ToggleFeatureInput {
    feature: String!
    enabled: Boolean!
}

operations.reducer:
if (action.input.enabled && !state.features.includes(action.input.feature)) {
    state.features.push(action.input.feature);
} else if (!action.input.enabled) {
    state.features = state.features.filter(f => f !== action.input.feature);
}
